import * as React from "react";
import Box from "@mui/material/Button";
import Cesar from '../images/me.JPG'
import { styled,createTheme } from '@mui/material/styles';

import { Grid, Typography } from "@mui/material";




const StyledImage = styled(new Image)`
  ${({ theme }) => `
  cursor: pointer;
  background-color: ${theme.palette.primary.main};
  transition: ${theme.transitions.create(['background-color', 'transform'], {
    duration: theme.transitions.duration.standard,
  })};
  &:hover {
    background-color: ${theme.palette.secondary.main};
    transform: scale(1.3);
  }
  `}
`;
export const Body = () => {

    const skills=[{
        id:1,
        name:'HTML'
    },
{
    id:2,
    name:'CSS'
}]
  return (
    <Grid container spacing={2} mt={2} >
      <Grid item xs={6}>
        <Typography variant="h2">Hello My Name is Cesar</Typography>

        <Typography variant='body1'>Analytical thinker skilled in developing responsive web and mobile applications using React and Angular, I bring two years of experience in Frontend Development and Quality Assurance. Proficient in ensuring top-notch production quality through strategic implementation of automated processes, I navigate complex manufacturing workflows with ease. My collaborative nature thrives in cross-functional team environments, where I consistently contribute innovative ideas to drive product and engineering excellence. </Typography>
    {skills.map((skill)=>(
     <Box component='div' key={skill.id} mt={2}>
        <Typography variant="h3">{skill.name}</Typography>

     </Box>

))}
      </Grid>

      <Grid item xs={6} display='flex' justifyContent='center'>
        <img src={Cesar}  style={{maxWidth:'300px',objectFit:'cover',borderRadius:'100px 200px 300px 200px'}}>
        </img>
        <StyledImage/>
      </Grid>
    </Grid>
  );
};
